# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

class Account:
    def __init__(self, balance=0):
        self.balance = balance

    def deposit(self, amount):
        if amount > 0:
            self.balance += amount
            return True
        else:
            print("Invalid deposit amount")
            return False

    def withdraw(self, amount):
        if amount <= self.balance:
            self.balance -= amount
            return True
        else:
            print("Insufficient funds")
            return False

    def get_balance(self):
        return self.balance

def process_transaction(account, transaction):
    operation, amount = transaction
    if operation == "deposit":
        account.deposit(amount)
    elif operation == "withdraw":
        account.withdraw(amount)
    else:
        print("Invalid transaction type")

# Example usage:
account = Account()
transactions = [("deposit", 100), ("withdraw", 50), ("deposit", 200)]
for transaction in transactions:
    process_transaction(account, transaction)
print(account.get_balance())